#include "behavior_planner/feature/object_projector.hpp"
namespace behavior_planner { ObjectFeature ObjectProjector::project(const TrackedObject&o,const EgoFeature&e,const RouteManager&r)const{ObjectFeature f;f.type=o.type;f.id=o.id;f.x=o.x;f.y=o.y;f.yaw=o.yaw;f.speed=o.speed;f.accel=o.accel;f.length=o.length;f.width=o.width;std::string route_link;bool route_valid=r.projectEgo(o.x,o.y,&f.s,&f.d,&route_link);LinkProjection map_projection;bool map_valid=r.matchMapLink(o.x,o.y,o.yaw,&map_projection);f.valid=route_valid&&map_valid;if(map_valid){f.link_id=map_projection.link_id;f.link_s=map_projection.link_s;}f.gap=f.s-e.s;f.relative_speed=e.speed-o.speed;f.ttc=(f.gap>0&&f.relative_speed>0)?f.gap/f.relative_speed:1e9;return f;} }
